parameters.bodyParametersJson:
={
  "model": "llama2",
  "prompt": "You are a security patch expert. Generate detailed patch recommendations for this vulnerability:

CVE: {{ $json.cve_id }}
Title: {{ $json.vulnerability_title }}
Description: {{ $json.description }}
Affected Component: {{ $json.affected_component }}
CVSS Score: {{ $json.cvss_score }}

Provide:
1. Patch title and version
2. Detailed description of the fix
3. Step-by-step remediation actions
4. Pre-patch checklist items
5. Estimated time to apply
6. Whether restart is required
7. Verification steps

Format as JSON with keys: title, version, description, actions (array), checklist (array), estimated_time_minutes, requires_restart, verification_steps (array)",
  "stream": false
}

parameters.functionCode:
// Parse Ollama response and format patch recommendations
const ollamaResponse = items[0].json.response;

let patchData;
try {
  // Try to extract JSON from response
  const jsonMatch = ollamaResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    patchData = JSON.parse(jsonMatch[0]);
  } else {
    // Fallback: create structured patch from text
    patchData = {
      title: `Security Patch for ${items[0].json.cve_id}`,
      version: "1.0.0",
      description: ollamaResponse.substring(0, 200),
      actions: [
        "Review vulnerability details",
        "Apply security updates",
        "Test functionality",
        "Verify fix"
      ],
      checklist: [
        "Backup system",
        "Notify stakeholders",
        "Schedule maintenance window"
      ],
      estimated_time_minutes: 30,
      requires_restart: true,
      verification_steps: [
        "Run security scan",
        "Verify vulnerability is patched"
      ]
    };
  }
} catch (error) {
  patchData = {
    title: `Patch for ${items[0].json.cve_id}`,
    error: error.message,
    raw_response: ollamaResponse
  };
}

return [
  {
    json: {
      patch_id: `patch_${Date.now()}`,
      vulnerability_id: items[0].json.cve_id,
      ...patchData,
      status: "pending",
      generated_at: new Date().toISOString(),
      generated_by: "ai"
    }
  }
];
